<?php
namespace Tests\Feature\Payouts;
use App\Domain\Payouts\Actions\CreatePayout;use App\Domain\Payouts\Actions\ProcessPayout;use App\Enums\PayoutStatus;use App\Enums\PayoutType;use App\Models\Cooperative;use App\Models\User;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Auth;use Illuminate\Validation\ValidationException;use Tests\TestCase;
class PayoutLifecycleTest extends TestCase{use RefreshDatabase;public function test_payout_is_idempotent_and_enforces_maker_checker():void{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);$maker=User::factory()->create(['cooperative_id'=>$cooperative->id]);$checker=User::factory()->create(['cooperative_id'=>$cooperative->id]);Auth::login($maker);$data=['idempotency_key'=>'welfare-001','type'=>PayoutType::WelfareBenefit,'amount_minor'=>50000,'beneficiary_name'=>'Member One','bank_code'=>'001','account_number'=>'0123456789'];$first=app(CreatePayout::class)->execute($data);$second=app(CreatePayout::class)->execute($data);$this->assertTrue($first->is($second));try{app(ProcessPayout::class)->approve($first);$this->fail('Maker approval should fail.');}catch(ValidationException){}Auth::login($checker);$approved=app(ProcessPayout::class)->approve($first);$this->assertSame(PayoutStatus::Approved,$approved->status);$this->assertSame('6789',$approved->account_number_last_four);}}
